          // The union covers [0, max(CX-1, MaxX)] = [0, MaxX].
          // So result is icmp ult X, MaxX+1.
          APInt NewCX = MaxX + 1;
          // But we must ensure no overflow
          if (NewCX.ugt(MaxX)) {
            return Builder.CreateICmp(ICmpInst::ICMP_ULT, X,
                                      ConstantInt::get(X->getType(), NewCX));
          }
        }
      }
    }

